import React, { useContext, useEffect } from 'react';
import { Card, CardContent, Typography, Grid, Container, Box, Button } from '@mui/material';
import { useHistory } from 'react-router-dom';
import HistoryContext from '../../context/history/historyContext';
import AuthContext from '../../context/auth/authContext';

const Home = () => {
  const historyContext = useContext(HistoryContext);
  const authContext = useContext(AuthContext);
  const history = useHistory();

  const { games, updateCurrentLevel, getGames } = historyContext;

  // Load user and games data from backend
  useEffect(() => {
    authContext.loadUser();
    getGames();
    // eslint-disable-next-line
  }, []);

  // Calculate average moves
  const getAvg = (data) => {
    const gameArr = data[0]
      .filter((game) => game.gameLevel === data[1])
      .map((game) => game.numOfMoves);

    return gameArr.length > 0
      ? Math.floor(gameArr.reduce((a, b) => a + b) / gameArr.length)
      : 'No games played';
  };

  // Navigate back to levels
  const goBack = () => {
    history.push('/levels'); // Adjust path according to your route setup
  };

  return (
    !authContext.loading && (
      <Box
        sx={{
          minHeight: '100vh',
          background: 'linear-gradient(135deg, #1c1e5a 30%, #5b1e7d 90%)',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
        }}
      >
        <Container maxWidth="md" sx={{ py: 4 }}>
          <Card sx={{ backgroundColor: 'primary.main', color: 'white', padding: '24px' }}>
            <CardContent>
              <Typography variant="h4" align="center" gutterBottom sx={{ fontWeight: 'bold' }}>
                Welcome Back!
              </Typography>
              <Typography variant="h6" align="center">
                You have played {games.length} {games.length === 1 ? 'game' : 'games'} so far!
              </Typography>

              <Typography variant="h5" align="center" sx={{ mt: 2, fontWeight: 'medium' }}>
                Average Moves:
              </Typography>

              {/* Level Titles and Averages */}
              <Grid container spacing={2} sx={{ mt: 3 }}>
                <Grid item xs={4}>
                  <Typography variant="h6" align="center">Easy</Typography>
                  <Typography variant="body1" align="center">
                    {getAvg([games, 'beginner'])}
                  </Typography>
                </Grid>
                <Grid item xs={4}>
                  <Typography variant="h6" align="center">Medium</Typography>
                  <Typography variant="body1" align="center">
                    {getAvg([games, 'intermediate'])}
                  </Typography>
                </Grid>
                <Grid item xs={4}>
                  <Typography variant="h6" align="center">Hard</Typography>
                  <Typography variant="body1" align="center">
                    {getAvg([games, 'expert'])}
                  </Typography>
                </Grid>
              </Grid>

              {/* Back to Levels Button */}
              <Box sx={{ mt: 4, display: 'flex', justifyContent: 'center' }}>
                <Button 
                  variant="contained" 
                  color="secondary" 
                  onClick={goBack}
                >
                  Back to Levels
                </Button>
              </Box>
            </CardContent>
          </Card>
        </Container>
      </Box>
    )
  );
};

export default Home;
